function chunk(array, size) {
  const out = [];
  for (let i = 0; i < array.length; i += size) {
    out.push(array.slice(i, i + size));
  }
  return out;
}

function flatten(xs) {
  return xs.reduce((a, x) => a.concat(Array.isArray(x) ? flatten(x) : x), []);
}

module.exports = { chunk, flatten };
